import React from 'react';

interface OrderCardProps {
  orderId: string;
  customerName: string;
  status: string;
  totalAmount: number;
  onStatusChange: (orderId: string, newStatus: string) => void;
}

const OrderCard: React.FC<OrderCardProps> = ({ orderId, customerName, status, totalAmount, onStatusChange }) => {
  const handleStatusChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    onStatusChange(orderId, event.target.value);
  };

  return (
    <div className="bg-gray-800 p-4 rounded-xl shadow-md hover:shadow-lg transition-shadow">
      <div className="flex justify-between items-center mb-2">
        <h3 className="text-white font-semibold">Order #{orderId}</h3>
        <span className={`text-sm px-2 py-1 rounded-full ${status === 'Pending' ? 'bg-yellow-500' : status === 'Shipped' ? 'bg-blue-500' : 'bg-green-500'} text-white`}>{status}</span>
      </div>
      <p className="text-gray-400 mb-2">Customer: {customerName}</p>
      <p className="text-gray-400 mb-4">Total: ${totalAmount.toFixed(2)}</p>
      <div className="flex justify-between items-center">
        <select
          value={status}
          onChange={handleStatusChange}
          className="bg-gray-700 text-white rounded-lg px-3 py-1 focus:outline-none focus:ring-2 focus:ring-indigo-500"
        >
          <option value="Pending">Pending</option>
          <option value="Shipped">Shipped</option>
          <option value="Completed">Completed</option>
        </select>
        <button className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-500 transition">View Details</button>
      </div>
    </div>
  );
};

export default OrderCard;

